import { ethers } from 'ethers';

const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function balanceOf(address account) external view returns (uint256)"
];

const DEX_ABI = [
  "function swap(address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOutMin, address to, uint256 deadline) external"
];

const MAX_UINT256 = ethers.constants.MaxUint256;

async function approveToken(tokenAddress, spenderAddress) {
  const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, signer);
  const tx = await tokenContract.approve(spenderAddress, MAX_UINT256);
  await tx.wait();
  console.log('Approval successful');
}

async function swapTokens(dexAddress, tokenIn, tokenOut, amountIn, amountOutMin, deadline) {
  const dexContract = new ethers.Contract(dexAddress, DEX_ABI, signer);
  const tx = await dexContract.swap(tokenIn, tokenOut, amountIn, amountOutMin, await signer.getAddress(), deadline);
  await tx.wait();
  console.log('Swap successful');
}

async function checkAllowance(tokenAddress, ownerAddress, spenderAddress) {
  const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, provider);
  const allowance = await tokenContract.allowance(ownerAddress, spenderAddress);
  console.log(`Allowance: ${allowance.toString()}`);
  return allowance;
}

async function checkBalance(tokenAddress, accountAddress) {
  const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, provider);
  const balance = await tokenContract.balanceOf(accountAddress);
  console.log(`Balance: ${balance.toString()}`);
  return balance;
}

